#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int A, B, C; scanf("%d %d %d", &A, &B, &C);
        bool visited[200][200] = {false};
        int step = 0;
        int best = A*100 + B;
        int answer = 0;
        visited[A][B] = true;
        while (1) {
            int nextA, nextB;
            if (B >= C) {
                nextA = B - C;
                nextB = A;
            } else if (A > 0) {
                nextA = B + 100 - C;
                nextB = A - 1;
            } else {
                break;
            }
            step++;
            int cur = nextA*100 + nextB;
            if (cur > best) { best = cur; answer = step; }
            if (visited[nextA][nextB]) break;
            visited[nextA][nextB] = true;
            A = nextA; B = nextB;
        }
        printf("%d\n", answer);
    }
    return 0;
}

